import { createContext, useContext, useState, useEffect, useRef } from "react";
import axios from "axios";
import { setToken } from "../tokenStore";

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const initialized = useRef(false);

  // On page load, attempt a silent refresh using the HttpOnly cookie.
  // If the cookie is present (and not expired), we get a new access token back.
  useEffect(() => {
    if (initialized.current) return;
    initialized.current = true;

    axios
      .post("http://localhost:5000/api/auth/refresh-token", {}, { withCredentials: true })
      .then((res) => {
        setToken(res.data.token);
        setUser(res.data.user);
      })
      .catch(() => {
        setToken(null);
        setUser(null);
      })
      .finally(() => setLoading(false));
  }, []);

  const setAuth = (token, userData) => {
    setToken(token);
    setUser(userData);
  };

  const clearAuth = () => {
    setToken(null);
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, loading, setAuth, clearAuth }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);
